con:config.script:
def documentTime = '/urn:vaccinationMedicalRecord/urn1:vaccinationMedicalRecordHeader/urn1:documentTime'
def authorTime = '/urn:vaccinationMedicalRecord/urn1:vaccinationMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def signatureTime = '/urn:vaccinationMedicalRecord/urn1:vaccinationMedicalRecordHeader/urn1:legalAuthenticator/urn1:signatureTime'
def regRecordDate = '/urn:vaccinationMedicalRecord/urn1:vaccinationMedicalRecordBody/urn1:registrationRecord/urn1:date'
def dateFormat = 'yyyyMMdd'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.iteration) {
	def documentTimes = context.allRecords.collect { record -> record.firstElementAt(documentTime) }
	def authorTimes = context.allRecords.collect { record -> record.firstElementAt(authorTime) }
	def signatureTimes = context.allRecords.collect { record -> record.firstElementAt(signatureTime) }
	def regRecordDates = context.allRecords.collect { record -> record.firstElementAt(regRecordDate) }

	def dates = (documentTimes + authorTimes + signatureTimes + regRecordDates).findAll().collect{ it[0..7] }.sort()
	context.firstDate = Date.parse(dateFormat, dates[0])
	context.lastDate = Date.parse(dateFormat, dates[-1])
	context.iteration = 1
}

def dateDiff = context.lastDate - context.firstDate
def randomOffsets = (0..1).collect { (Math.random() * (dateDiff+1)).toInteger()}
def dates = randomOffsets.collect{ context.firstDate.plus(it).format(dateFormat) }.sort()

context.timePeriodStart = dates[0]
context.timePeriodEnd = dates[-1]

[context.timePeriodStart, context.timePeriodEnd]

